using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2 }, 10, 3, 5);

            // Assert
            Assert.AreEqual(3, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_CalculatesTotalPages()
        {
            // 10 items, pageSize 3 → ceil(10/3) = 4
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);

            Assert.AreEqual(4, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 20, 1, 5);

            Assert.AreEqual(3, list.Count);
            Assert.AreEqual("a", list[0]);
            Assert.AreEqual("b", list[1]);
            Assert.AreEqual("c", list[2]);
        }

        [TestMethod]
        public void Constructor_TotalPagesRoundsUp()
        {
            // 7 items, pageSize 3 → ceil(7/3) = 3
            var list = new PaginatedList<int>(new List<int>(), 7, 1, 3);

            Assert.AreEqual(3, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_ExactDivision_NoExtraPage()
        {
            // 9 items, pageSize 3 → ceil(9/3) = 3
            var list = new PaginatedList<int>(new List<int>(), 9, 1, 3);

            Assert.AreEqual(3, list.TotalPages);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            // 10 items, pageSize 5 → 2 total pages; page 2 is last
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_FirstPageOfMany_ReturnsTrue()
        {
            // 10 items, pageSize 5 → 2 total pages; page 1 has next
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasPreviousPage_SinglePage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act - page 2, page size 5
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages); // 20/5 = 4
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);  // items 6-10 on page 2
            Assert.AreEqual(10, result[4]);
        }

        [TestMethod]
        public void Create_FirstPage_HasCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 12).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages); // ceil(12/5) = 3
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
        }

        [TestMethod]
        public void Create_LastPagePartial_HasRemainingItems()
        {
            // Arrange - 7 items, page size 5, page 2 should have 2 items
            var source = Enumerable.Range(1, 7).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(2, result.TotalPages);
            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(7, result[1]);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<string>().AsQueryable();

            // Act
            var result = PaginatedList<string>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(0, result.TotalPages);
        }

        [TestMethod]
        public void Create_SingleItem_SinglePage()
        {
            // Arrange
            var source = new[] { "only" }.AsQueryable();

            // Act
            var result = PaginatedList<string>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(1, result.TotalPages);
            Assert.AreEqual("only", result[0]);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }
    }
}

