using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public sealed class PersonTests
    {
        // Person is abstract, so we test via Student (a concrete subclass)

        [TestMethod]
        public void FullName_ConcatenatesLastNameCommaFirstName()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Today
            };

            // Act
            var fullName = student.FullName;

            // Assert
            Assert.AreEqual("Smith, John", fullName);
        }

        [TestMethod]
        public void FullName_WithSingleCharNames_FormatsCorrectly()
        {
            // Arrange
            var student = new Student
            {
                LastName = "X",
                FirstMidName = "Y",
                EnrollmentDate = DateTime.Today
            };

            // Act & Assert
            Assert.AreEqual("X, Y", student.FullName);
        }

        [TestMethod]
        public void FullName_ViaInstructor_WorksSameWay()
        {
            // Person.FullName should work the same for all subclasses
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = DateTime.Today
            };

            Assert.AreEqual("Doe, Jane", instructor.FullName);
        }

        [TestMethod]
        public void ID_CanBeSetAndRetrieved()
        {
            var student = new Student
            {
                ID = 42,
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.Today
            };

            Assert.AreEqual(42, student.ID);
        }
    }
}

