using System;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void TestInitialize()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateContext();
            _controller = new StudentsController(_context);
        }

        [TestCleanup]
        public void TestCleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        private Student CreateStudent(string firstName = "John", string lastName = "Doe", DateTime? enrollmentDate = null)
        {
            var student = new Student
            {
                FirstMidName = firstName,
                LastName = lastName,
                EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();
            return student;
        }

        // ===================== Index Tests =====================

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithAllStudents()
        {
            // Arrange
            CreateStudent("Alice", "Adams");
            CreateStudent("Bob", "Brown");

            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            // Arrange
            CreateStudent("Charlie", "Zeta");
            CreateStudent("Alice", "Alpha");

            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual("Alpha", model[0].LastName);
            Assert.AreEqual("Zeta", model[1].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            // Arrange
            CreateStudent("Alice", "Alpha");
            CreateStudent("Charlie", "Zeta");

            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual("Zeta", model[0].LastName);
            Assert.AreEqual("Alpha", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            // Arrange
            CreateStudent("Late", "Starter", new DateTime(2023, 9, 1));
            CreateStudent("Early", "Bird", new DateTime(2020, 1, 1));

            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual("Bird", model[0].LastName);
            Assert.AreEqual("Starter", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            // Arrange
            CreateStudent("Early", "Bird", new DateTime(2020, 1, 1));
            CreateStudent("Late", "Starter", new DateTime(2023, 9, 1));

            // Act
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual("Starter", model[0].LastName);
            Assert.AreEqual("Bird", model[1].LastName);
        }

        [TestMethod]
        public void Index_SearchByLastName_FiltersCorrectly()
        {
            // Arrange
            CreateStudent("Alice", "Smith");
            CreateStudent("Bob", "Jones");
            CreateStudent("Charlie", "Smith");

            // Act
            var result = _controller.Index(null, null, "Smith", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual(2, model.Count);
            Assert.IsTrue(model.All(s => s.LastName == "Smith"));
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            // Arrange
            CreateStudent("Alice", "Smith");
            CreateStudent("Bob", "Jones");

            // Act
            var result = _controller.Index(null, null, "Alice", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alice", model[0].FirstMidName);
        }

        [TestMethod]
        public void Index_NewSearch_ResetsPageToOne()
        {
            // Arrange
            CreateStudent("Alice", "Smith");

            // Act - searchString != null should set page to 1
            var result = _controller.Index(null, null, "Smith", 5) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NoSearch_UsesCurrentFilter()
        {
            // Arrange
            CreateStudent("Alice", "Smith");
            CreateStudent("Bob", "Jones");

            // Act - searchString is null, currentFilter is "Smith"
            var result = _controller.Index(null, "Smith", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Smith", model[0].LastName);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_NameDescSort_SetsToggleToDefault()
        {
            // When sortOrder is "name_desc", NameSortParm should be "" (toggle back to asc)
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.AreEqual("", _controller.ViewBag.NameSortParm);
        }

        [TestMethod]
        public void Index_DateSort_SetsDateToggleToDesc()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
        }

        // ===================== Details Tests =====================

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
