            var student = CreateStudent("Alice", "Smith");

            // Act
            var result = _controller.Details(student.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual("Alice", model.FirstMidName);
            Assert.AreEqual("Smith", model.LastName);
        }

        // ===================== Create (GET) Tests =====================

        [TestMethod]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        // ===================== Create (POST) Tests =====================

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            var result = _controller.Create(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);

            // Verify student was saved
            Assert.AreEqual(1, _context.Students.Count());
            var saved = _context.Students.First();
            Assert.AreEqual("New", saved.FirstMidName);
            Assert.AreEqual("Student", saved.LastName);
        }

        [TestMethod]
        public void Create_Post_MinValueDate_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Bad",
                LastName = "Date",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_Post_DateBeforeSqlMin_AddsModelError()
        {
            // Arrange — date before 1753-01-01
            var student = new Student
            {
                FirstMidName = "Old",
                LastName = "Date",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

