        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };
            _controller.ModelState.AddModelError("LastName", "Required");

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual(0, _context.Students.Count()); // Not saved
        }

        [TestMethod]
        public void Create_Post_ValidStudent_SendsNotification()
        {
            // Arrange
            TestHelper.DrainNotificationQueue();
            var student = new Student
            {
                FirstMidName = "Notify",
                LastName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            _controller.Create(student);

            // Assert — notification was sent
            var service = new ContosoUniversity.Services.NotificationService();
            var notification = service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("CREATE", notification.Operation);
        }

        // ===================== Edit (GET) Tests =====================

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var student = CreateStudent("Edit", "Me");

            // Act
            var result = _controller.Edit(student.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual("Edit", model.FirstMidName);
        }

        // ===================== Edit (POST) Tests =====================

