        public void Edit_Post_MinValueDate_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _controller.Edit(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };
            _controller.ModelState.AddModelError("Name", "Error");

            // Act
            var result = _controller.Edit(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // ===================== Delete (GET) Tests =====================

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
