            // which tests the error handling path
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Verifiable();

            // Act
            var result = _controller.Create(course, mockFile.Object);

            // Assert - should NOT have the extension error
            if (_controller.ModelState.ContainsKey("teachingMaterialImage"))
            {
                var errors = _controller.ModelState["teachingMaterialImage"].Errors;
                Assert.IsFalse(errors.Any(e => e.ErrorMessage.Contains("valid image file")),
                    $"Extension {extension} should be valid but was rejected");
            }
        }

