            // Arrange - exactly 5MB should pass (> 5MB fails)
            var dept = CreateDepartment();
            var course = new Course
            {
                CourseID = 8888,
                Title = "Size Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var mockFile = CreateMockFile("exact.png", 5 * 1024 * 1024); // exactly 5MB
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Verifiable();

            // Act
            var result = _controller.Create(course, mockFile.Object);

            // Assert - should NOT have size error
            if (_controller.ModelState.ContainsKey("teachingMaterialImage"))
            {
                var errors = _controller.ModelState["teachingMaterialImage"].Errors;
                Assert.IsFalse(errors.Any(e => e.ErrorMessage.Contains("5MB")),
                    "File of exactly 5MB should pass size validation");
            }
        }
