        [TestMethod]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            Assert.IsNotNull(value);
            // Check the anonymous object has the expected properties
            var successProp = value.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.IsNotNull(countProp);
            Assert.AreEqual(0, countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange - enqueue some notifications
            var service = new NotificationService();
            service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
            service.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.AreEqual(2, countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_MoreThan10_LimitsTo10()
        {
            // Arrange - enqueue 15 notifications
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Item", i.ToString(), EntityOperation.CREATE);
            }

            // Act
            var result = _controller.GetNotifications();

            // Assert
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.AreEqual(10, countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_DequeuedItemsNotReturnedAgain()
        {
            // Arrange
            var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE);

            // Act - first call dequeues
            _controller.GetNotifications();
            // Second call should be empty
            var result = _controller.GetNotifications();

            // Assert
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.AreEqual(0, countProp.GetValue(value));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            // Act
            var result = _controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(value));
        }

        [TestMethod]
        public void MarkAsRead_ArbitraryId_StillReturnsSuccess()
        {
            // The MarkAsRead is a no-op, so any ID should succeed
            var result = _controller.MarkAsRead(999);

            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(value));
        }
    }
}

