        [TestInitialize]
        public void TestInitialize()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateContext();
            _controller = new InstructorsController(_context);
        }

        [TestCleanup]
        public void TestCleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
