        private Instructor CreateInstructor(string firstName = "Kim", string lastName = "Abercrombie",
            DateTime? hireDate = null, bool withOffice = false)
        {
            var instructor = new Instructor
            {
                FirstMidName = firstName,
                LastName = lastName,
                HireDate = hireDate ?? new DateTime(2010, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            if (withOffice)
            {
                instructor.OfficeAssignment = new OfficeAssignment
                {
                    Location = "Room 101"
                };
            }
            _context.Instructors.Add(instructor);
