            // Assert
            Assert.AreEqual(5, context.Instructors.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsDepartments()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(4, context.Departments.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsCourses()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsEnrollments()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(11, context.Enrollments.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsCourseAssignments()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(8, context.CourseAssignments.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.AreEqual(3, context.OfficeAssignments.Count());
        }

        [TestMethod]
        public void Initialize_NonEmptyDatabase_DoesNotDuplicateData()
        {
            // Arrange
            using var context = TestHelper.CreateContext();
            // Pre-seed one student
            context.Students.Add(new Student
            {
                FirstMidName = "Existing",
                LastName = "Student",
                EnrollmentDate = DateTime.Today
            });
            context.SaveChanges();

            // Act
            DbInitializer.Initialize(context);

            // Assert - should still have only the 1 pre-existing student (no seed because DB is not empty)
            Assert.AreEqual(1, context.Students.Count());
            Assert.AreEqual("Existing", context.Students.First().FirstMidName);
        }

        [TestMethod]
        public void Initialize_CalledTwice_DoesNotDuplicate()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);
            DbInitializer.Initialize(context); // second call

            // Assert - counts should be the same as after first call
            Assert.AreEqual(8, context.Students.Count());
            Assert.AreEqual(5, context.Instructors.Count());
            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_SeedsSpecificStudentNames()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert - verify specific seeded data
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Alexander" && s.FirstMidName == "Carson"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Alonso" && s.FirstMidName == "Meredith"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Olivetto" && s.FirstMidName == "Nino"));
        }

        [TestMethod]
        public void Initialize_SeedsDepartmentNames()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.IsTrue(context.Departments.Any(d => d.Name == "English"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Mathematics"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Engineering"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Economics"));
        }

        [TestMethod]
        public void Initialize_SeedsCourseTitles()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.IsTrue(context.Courses.Any(c => c.Title == "Chemistry" && c.CourseID == 1050));
            Assert.IsTrue(context.Courses.Any(c => c.Title == "Calculus" && c.CourseID == 1045));
            Assert.IsTrue(context.Courses.Any(c => c.Title == "Literature" && c.CourseID == 2042));
        }

        [TestMethod]
        public void Initialize_SeedsEnrollmentsWithGrades()
        {
            // Arrange
            using var context = TestHelper.CreateContext();

            // Act
            DbInitializer.Initialize(context);

            // Assert - check that some enrollments have grades and some don't
            Assert.IsTrue(context.Enrollments.Any(e => e.Grade == Grade.A));
            Assert.IsTrue(context.Enrollments.Any(e => e.Grade == Grade.B));
            Assert.IsTrue(context.Enrollments.Any(e => e.Grade == null)); // Anand's Chemistry enrollment has no grade
        }
    }
}

